const rows = $input.all().map(r => r.json);
const sheetName = $('Compute Previous Week Sheet Name').first().json.current_week_sheet;

// ─── Helpers ──────────────────────────────────────────────
const toFloat  = v => { const n = parseFloat(v); return isNaN(n) ? 0 : n; };
const toInt    = v => { const n = parseInt(v);   return isNaN(n) ? 0 : n; };
const toBool   = v => v === true || v === 'true' || v === 'TRUE';
const isEmpty  = v => v === null || v === undefined || String(v).trim() === '';

// ─── Extraire la semaine ISO depuis le nom de la sheet ────
// Format attendu : WEEK16_2026
const sheetWeekMatch = sheetName?.match(/WEEK(\d+)_(\d+)/);
const sheetWeek = sheetWeekMatch ? parseInt(sheetWeekMatch[1]) : null;
const sheetYear = sheetWeekMatch ? parseInt(sheetWeekMatch[2]) : null;

const getISOWeek = (dateStr) => {
  const d = new Date(dateStr.replace(' ', 'T'));
  if (isNaN(d)) return null;
  const iso = new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));
  iso.setUTCDate(iso.getUTCDate() + 4 - (iso.getUTCDay() || 7));
  const yearStart = new Date(Date.UTC(iso.getUTCFullYear(), 0, 1));
  return {
    week: Math.ceil((((iso - yearStart) / 86400000) + 1) / 7),
    year: iso.getUTCFullYear(),
  };
};

const PRICE_THRESHOLD = 50000;

// ════════════════════════════════════════════════════════════
// CHECK 1 — Doublons line_item_id
// ════════════════════════════════════════════════════════════
const lineItemCount = {};
for (const row of rows) {
  const id = String(row.line_item_id);
  lineItemCount[id] = (lineItemCount[id] || 0) + 1;
}
const duplicateLineItems = Object.entries(lineItemCount)
  .filter(([_, c]) => c > 1)
  .map(([id, occurrences]) => {
    const example = rows.find(r => String(r.line_item_id) === id);
    return {
      line_item_id: id,
      occurrences,
      order_number: example?.order_number,
      product_name: example?.product_name,
    };
  });

// ════════════════════════════════════════════════════════════
// CHECK 2 — Doublons order_id (commande entière dupliquée)
// Détecte si le même order_id apparaît avec des line_item_id
// différents mais un nombre de lignes × 2 — signe que tout
// le run a été réécrit deux fois
// ════════════════════════════════════════════════════════════
const orderLineItems = {};
for (const row of rows) {
  const oid = String(row.order_id);
  if (!orderLineItems[oid]) orderLineItems[oid] = [];
  orderLineItems[oid].push(row.line_item_id);
}

const duplicateOrders = [];
for (const [oid, lineIds] of Object.entries(orderLineItems)) {
  const uniqueLineIds = new Set(lineIds);
  // Si le total de lignes > unique line_item_ids → doublons dans cette commande
  if (lineIds.length > uniqueLineIds.size) {
    duplicateOrders.push({
      order_id:       oid,
      order_number:   rows.find(r => String(r.order_id) === oid)?.order_number,
      total_rows:     lineIds.length,
      unique_items:   uniqueLineIds.size,
      duplicate_rows: lineIds.length - uniqueLineIds.size,
    });
  }
}

// ════════════════════════════════════════════════════════════
// CHECK 3 — Cohérence financière
// ════════════════════════════════════════════════════════════
const financialAnomalies = [];

for (const row of rows) {
  const unit_price       = toFloat(row.unit_price);
  const total_line_price = toFloat(row.total_line_price);
  const total_discount   = toFloat(row.total_discount);
  const quantity         = toInt(row.quantity);

  // 3a. unit_price × quantity ≠ total_line_price (tolérance 0.02)
  const expected = Math.round(unit_price * quantity * 100) / 100;
  const actual   = Math.round(total_line_price * 100) / 100;
  if (Math.abs(expected - actual) > 0.02) {
    financialAnomalies.push({
      row_number:    row.row_number,
      order_number:  row.order_number,
      line_item_id:  row.line_item_id,
      product_name:  row.product_name,
      issue:         'unit_price × quantity ≠ total_line_price',
      expected,
      actual,
      diff: Math.round((actual - expected) * 100) / 100,
    });
  }

  // 3b. Prix unitaire aberrant
  if (unit_price > PRICE_THRESHOLD) {
    financialAnomalies.push({
      row_number:   row.row_number,
      order_number: row.order_number,
      line_item_id: row.line_item_id,
      product_name: row.product_name,
      issue:        `unit_price aberrant : ${unit_price}`,
    });
  }

  // 3c. total_line_price = 0 mais unit_price > 0
  if (total_line_price === 0 && unit_price > 0) {
    financialAnomalies.push({
      row_number:   row.row_number,
      order_number: row.order_number,
      line_item_id: row.line_item_id,
      product_name: row.product_name,
      issue:        'total_line_price est 0 mais unit_price > 0',
    });
  }

  // 3d. total_discount négatif
  if (total_discount < 0) {
    financialAnomalies.push({
      row_number:   row.row_number,
      order_number: row.order_number,
      line_item_id: row.line_item_id,
      product_name: row.product_name,
      issue:        `total_discount négatif : ${total_discount}`,
    });
  }

  // 3e. quantity ≤ 0
  if (quantity <= 0) {
    financialAnomalies.push({
      row_number:   row.row_number,
      order_number: row.order_number,
      line_item_id: row.line_item_id,
      product_name: row.product_name,
      issue:        `quantity invalide : ${quantity}`,
    });
  }
}

// ════════════════════════════════════════════════════════════
// CHECK 4 — Données manquantes / suspectes
// ════════════════════════════════════════════════════════════
const dataIssues = [];

for (const row of rows) {
  const issues = [];

  if (isEmpty(row.order_id))                      issues.push('order_id manquant');
  if (isEmpty(row.line_item_id))                  issues.push('line_item_id manquant');
  if (isEmpty(row.product_name))                  issues.push('product_name manquant');
  if (isEmpty(row.order_number))                  issues.push('order_number manquant');
  if (isEmpty(row.customer_name))                 issues.push('customer_name manquant');
  if (isEmpty(row.shipping_country))              issues.push('shipping_country vide');
  if (isEmpty(row.customer_email))                issues.push('customer_email vide');
  if (isEmpty(row.payment_method))                issues.push('payment_method manquant');
  if (isEmpty(row.currency))                      issues.push('currency manquante');
  if (isEmpty(row.inserted_at))   issues.push('inserted_at manquant');

  if (issues.length > 0) {
    dataIssues.push({
      row_number:    row.row_number,
      order_number:  row.order_number  || '?',
      customer_name: row.customer_name || '?',
      line_item_id:  row.line_item_id  || '?',
      product_name:  row.product_name  || '?',
      issues,
    });
  }
}

// ════════════════════════════════════════════════════════════
// CHECK 5 — Cohérence customer par order_id
// Même order_id avec customer_name ou currency différents
// ════════════════════════════════════════════════════════════
const orderMeta = {};
const orderInconsistencies = [];

for (const row of rows) {
  const oid = String(row.order_id);
  if (!orderMeta[oid]) {
    orderMeta[oid] = {
      customer_name: row.customer_name,
      currency:      row.currency,
      order_number:  row.order_number,
    };
  } else {
    if (row.customer_name !== orderMeta[oid].customer_name) {
      orderInconsistencies.push({
        order_id:     oid,
        order_number: row.order_number,
        row_number:   row.row_number,
        issue:        'customer_name incohérent sur le même order_id',
        expected:     orderMeta[oid].customer_name,
        found:        row.customer_name,
      });
    }
    if (row.currency !== orderMeta[oid].currency) {
      orderInconsistencies.push({
        order_id:     oid,
        order_number: row.order_number,
        row_number:   row.row_number,
        issue:        'currency incohérente sur le même order_id',
        expected:     orderMeta[oid].currency,
        found:        row.currency,
      });
    }
  }
}

// ════════════════════════════════════════════════════════════
// CHECK 6 — inserted_at hors fenêtre de la sheet
// ════════════════════════════════════════════════════════════
const wrongWeekRows = [];

if (sheetWeek && sheetYear) {
  for (const row of rows) {
    if (!row.inserted_at) continue;
    const w = getISOWeek(row.inserted_at);
    if (!w) continue;
    if (w.week !== sheetWeek || w.year !== sheetYear) {
      wrongWeekRows.push({
        row_number:   row.row_number,
        order_number: row.order_number,
        line_item_id: row.line_item_id,
        inserted_at:  row.inserted_at,
        issue:        `inserted_at appartient à WEEK${w.week}_${w.year} mais est dans ${sheetName}`,
      });
    }
  }
}

// ════════════════════════════════════════════════════════════
// CHECK 7 — is_custom_item incohérent
// is_custom_item=false mais sku ET variant vides ET product_name
// ne ressemble pas à un produit catalogue (heuristique simple)
// ════════════════════════════════════════════════════════════
const customItemInconsistencies = [];

for (const row of rows) {
  const isCustom = toBool(row.is_custom_item);
  const hasSku   = !isEmpty(row.sku);
  const hasVariant = !isEmpty(row.variant);

  // is_custom_item=true mais a un SKU → suspect
  if (isCustom && hasSku) {
    customItemInconsistencies.push({
      row_number:   row.row_number,
      order_number: row.order_number,
      line_item_id: row.line_item_id,
      product_name: row.product_name,
      issue:        'is_custom_item=true mais SKU présent',
    });
  }
}

// ════════════════════════════════════════════════════════════
// Synthèse
// ════════════════════════════════════════════════════════════
const totalOrders = Object.keys(orderLineItems).length;
const totalRows   = rows.length;

const hasAnomalies = duplicateLineItems.length > 0
                  || duplicateOrders.length > 0
                  || financialAnomalies.length > 0
                  || dataIssues.length > 0
                  || orderInconsistencies.length > 0
                  || wrongWeekRows.length > 0
                  || customItemInconsistencies.length > 0;

const status = hasAnomalies ? '⚠ ANOMALIES DETECTED' : '✅ ALL CLEAR';

return [{
  json: {
    sheet_name:      sheetName,
    audit_timestamp: new Date().toISOString(),
    status,
    summary: {
      total_rows:                   totalRows,
      total_orders:                 totalOrders,
      duplicate_line_items:         duplicateLineItems.length,
      duplicate_orders:             duplicateOrders.length,
      financial_anomalies:          financialAnomalies.length,
      data_issues:                  dataIssues.length,
      order_inconsistencies:        orderInconsistencies.length,
      wrong_week_rows:              wrongWeekRows.length,
      custom_item_inconsistencies:  customItemInconsistencies.length,
    },
    duplicateLineItems,
    duplicateOrders,
    financialAnomalies,
    dataIssues,
    orderInconsistencies,
    wrongWeekRows,
    customItemInconsistencies,
  }
}];

const now = new Date();

// Reculer de 7 jours → tombe forcément dans la semaine précédente
const prev = new Date(Date.UTC(
  now.getUTCFullYear(),
  now.getUTCMonth(),
  now.getUTCDate() - 7
));

const iso = new Date(prev);
iso.setUTCDate(iso.getUTCDate() + 4 - (iso.getUTCDay() || 7));
const yearStart = new Date(Date.UTC(iso.getUTCFullYear(), 0, 1));
const weekNumber = Math.ceil((((iso - yearStart) / 86400000) + 1) / 7);
const weekYear = iso.getUTCFullYear();

return [{ json: { current_week_sheet: `WEEK${weekNumber}_${weekYear}` } }];
